import{_ as a,g as s,h as n,S as r}from"./chunks/vitepress-theme-teek.Ck6NGmwp.js";const u=JSON.parse('{"title":"产品 Sense 学习与实践全景","description":"产品 Sense 学习与实践全景一览，涵盖 AI 产品观察、复合型人才成长、商业化思考及方法论总结等。","frontmatter":{"date":"2026-03-19T23:05:50.000Z","title":"产品 Sense 学习与实践全景","description":"产品 Sense 学习与实践全景一览，涵盖 AI 产品观察、复合型人才成长、商业化思考及方法论总结等。","sticky":1,"top":true,"categories":["产品 Sense","AI"],"coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/product_sense_bg.png","permalink":"/product-sense"},"headers":[],"relativePath":"10.产品 Sense/index.md","filePath":"10.产品 Sense/index.md"}'),i={name:"10.产品 Sense/index.md"};function t(o,e,l,d,c,h){return n(),s("div",null,[...e[0]||(e[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /10.产品 Sense.md for this page in Markdown format</div><h1 id="产品-sense-学习与实践全景" tabindex="-1">产品 Sense 学习与实践全景 <a class="header-anchor" href="#产品-sense-学习与实践全景" aria-label="Permalink to “产品 Sense 学习与实践全景”">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to “引言”">​</a></h2><p>在产品成功率不足 10% 的残酷市场中，产品 Sense 往往被误认为是某种不可复制的玄妙“直觉”。然而，它本质上是一套可拆解、可训练的思维模式，核心在于：在信息不完整、资源受限的环境下，依然能精准判断“做什么”与“不做什么”，从而确保团队在投入开发前始终是在“做对产品”。</p><p>解构这种产品 Sense 的<strong>基础在于对投入产出比（ROI）的极致追求与对人性的深度剖析</strong>：</p><ul><li>一方面，<strong>卓越的产品嗅觉意味着寻找“高杠杆解”</strong>，用最克制的技术复杂度去撬动最广泛且强烈的用户价值，果断规避为了技术而技术的伪需求陷阱。</li><li>另一方面，既需要<strong>设身处地感知用户的真实使用场景与情绪，又必须保持理性去追问痛点的根源</strong>，确保产品既不沦为臃肿的需求许愿池，也不变成缺乏人性温度的冰冷机器。</li></ul><p>随着应用架构向智能化演进，<strong>产品 Sense 正在经历从“功能交互设计”向“语境与思维路径构建”的深刻演进</strong>。在 AI 时代，稀缺的不再是生成答案的引擎，而是<strong>将模糊业务痛点结构化、转化为系统可执行的精确指令的“定义问题”能力</strong>。这就要求我们在构建智能应用时兼具翻译官与架构师的视角，为智能体设计无形的上下文窗口与严密的约束边界，让 AI 在精心编排的信息场域中，持续输出精准且可控的商业解法。</p><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/product_sense_bg.png" style="width:100%;border-radius:8px;margin-bottom:20px;" alt="about site background"><h2 id="ai-产品观察与拆解分析" tabindex="-1">AI 产品观察与拆解分析 <a class="header-anchor" href="#ai-产品观察与拆解分析" aria-label="Permalink to “AI 产品观察与拆解分析”">​</a></h2><ul><li><a href="/product-sense/perplexity-knowledge-worker">AI-powered 搜索引擎观察分析：Perplexity 与知识工作者</a></li></ul><h2 id="做-ai-时代的复合型人才" tabindex="-1">做 AI 时代的复合型人才 <a class="header-anchor" href="#做-ai-时代的复合型人才" aria-label="Permalink to “做 AI 时代的复合型人才”">​</a></h2><ul><li><a href="/product-sense/ai-native-composite-talents/">AI 原生时代的复合型人才，究竟需要怎样的特质？</a></li><li><a href="/product-sense/engineer-build-product-sense">当“实现”不再是壁垒：工程师如何构建 Product Sense？</a></li></ul><h2 id="产品-sense-与商业化" tabindex="-1">产品 Sense 与商业化 <a class="header-anchor" href="#产品-sense-与商业化" aria-label="Permalink to “产品 Sense 与商业化”">​</a></h2><ul><li><a href="/growth/books#_2-产品与商业">好书籍汇总与推荐</a></li><li><a href="/product-sense/small-rule-learn">《小而美：持续盈利的经营法则》读后感</a></li></ul><h2 id="方法论学习与总结-洞察力与经济学思维" tabindex="-1">方法论学习与总结：洞察力与经济学思维 <a class="header-anchor" href="#方法论学习与总结-洞察力与经济学思维" aria-label="Permalink to “方法论学习与总结：洞察力与经济学思维”">​</a></h2><ul><li><a href="/product-sense/insight-model">洞察力模型：如何看透产品与技术背后的系统逻辑？</a></li><li><a href="/product-sense/using-economics-thinking">用经济学思维做产品</a></li></ul>',16)])])}const g=a(i,[["render",t]]);export{u as __pageData,g as default};
